export type ItemType = 'sword' | 'amulet' | 'staff' | 'potion' | 'rune' | 'moonstone';

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface Customer {
  yearsWithMHPCO: number;
}

export interface Damage {
  itemType: string;
  amount: number;
}

export interface Incident {
  cause: string;
  damages: Damage[];
}

export interface QuoteStep {
  op: 'quote';
  items: Item[];
}

export interface ClaimStep {
  op: 'claim';
  policy: number;
  incident: Incident;
}

export type Step = QuoteStep | ClaimStep;

export interface Scenario {
  customer: Customer;
  steps: Step[];
}

export interface QuoteResult {
  premium: number;
}

export interface ClaimResult {
  payout: number;
  remainingCap: number;
}

export type StepResult = QuoteResult | ClaimResult;

export interface ScenarioResults {
  results: StepResult[];
}

const MAIN_ITEMS: Record<string, { insuranceValue: number; basePremium: number }> = {
  sword: { insuranceValue: 1000, basePremium: 100 },
  amulet: { insuranceValue: 600, basePremium: 60 },
  staff: { insuranceValue: 800, basePremium: 80 },
  potion: { insuranceValue: 400, basePremium: 40 },
};

const COMPONENT_TYPES = new Set(['rune', 'moonstone']);
const COMPONENT_VALUE = 250;
const COMPONENT_PREMIUM = 25;
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;
const DEDUCTIBLE = 100;
const PROCESSING_FEE = 5;

function isComponent(type: string): boolean {
  return COMPONENT_TYPES.has(type);
}

function isKnownType(type: string): boolean {
  return type in MAIN_ITEMS || isComponent(type);
}

function itemInsuranceValue(item: Item): number {
  if (isComponent(item.type)) return COMPONENT_VALUE;
  return MAIN_ITEMS[item.type].insuranceValue;
}

function itemBasePremium(item: Item): number {
  if (isComponent(item.type)) return COMPONENT_PREMIUM;
  return MAIN_ITEMS[item.type].basePremium;
}

function itemSurchargeMultiplier(item: Item): number {
  let m = 0;
  if (item.cursed) m += 0.5;
  if (typeof item.enchantment === 'number' && item.enchantment >= 5) m += 0.3;
  return m;
}

interface PremiumBreakdown {
  policyBase: number;
  itemSurcharges: number;
  insuranceSum: number;
}

function computeItemAndComponentBase(items: Item[]): PremiumBreakdown {
  let policyBase = 0;
  let itemSurcharges = 0;
  let insuranceSum = 0;

  const componentCounts: Record<string, Item[]> = {};
  for (const item of items) {
    if (isComponent(item.type)) {
      (componentCounts[item.type] ||= []).push(item);
    } else {
      const base = itemBasePremium(item);
      policyBase += base;
      itemSurcharges += base * itemSurchargeMultiplier(item);
      insuranceSum += itemInsuranceValue(item);
    }
  }

  for (const [, group] of Object.entries(componentCounts)) {
    const n = group.length;
    const blocks = Math.floor(n / BLOCK_SIZE);
    const remainder = n - blocks * BLOCK_SIZE;
    policyBase += blocks * BLOCK_PREMIUM + remainder * COMPONENT_PREMIUM;
    insuranceSum += n * COMPONENT_VALUE;
    for (const item of group) {
      const base = itemBasePremium(item);
      itemSurcharges += base * itemSurchargeMultiplier(item);
    }
  }

  return { policyBase, itemSurcharges, insuranceSum };
}

export interface QuoteContext {
  customer: Customer;
  quoteIndex: number; // zero-based: 0 = first quote in scenario
}

export function computeQuote(items: Item[], ctx: QuoteContext): { premium: number; insuranceSum: number } {
  for (const item of items) {
    if (!isKnownType(item.type)) {
      throw new Error(`Unknown item type: ${item.type}`);
    }
  }

  const { policyBase, itemSurcharges, insuranceSum } = computeItemAndComponentBase(items);

  let policyWideMultiplier = 1;
  if (ctx.customer.yearsWithMHPCO >= 2) policyWideMultiplier -= 0.2;
  policyWideMultiplier += 0.1; // first insurance always applies
  if (ctx.quoteIndex >= 1) policyWideMultiplier -= 0.15;

  const total = policyBase * policyWideMultiplier + itemSurcharges + PROCESSING_FEE;
  const premium = Math.ceil(total);

  return { premium, insuranceSum };
}

interface PolicyState {
  items: Item[];
  insuranceSum: number;
  cap: number;
  remainingCap: number;
}

function payoutForDamage(item: Item, amount: number): number {
  const dragon = item.material === 'dragon';
  const highEnch = typeof item.enchantment === 'number' && item.enchantment >= 8;

  let base: number;
  if (highEnch) {
    base = amount * 0.5;
  } else {
    base = amount;
  }
  // dragon material: full reimbursement of damage (overrides high-ench only if not also high-ench;
  // but spec: "both clauses apply; the 50% rule wins, then deductible")
  if (dragon && !highEnch) {
    base = amount;
  }
  return base - DEDUCTIBLE;
}

export function computeClaim(policy: PolicyState, incident: Incident): { payout: number; remainingCap: number } {
  if (!incident.damages || incident.damages.length === 0) {
    return { payout: 0, remainingCap: policy.remainingCap };
  }

  // Validate damages: count by itemType
  const policyCounts: Record<string, number> = {};
  for (const it of policy.items) {
    policyCounts[it.type] = (policyCounts[it.type] || 0) + 1;
  }
  const damageCounts: Record<string, number> = {};
  for (const d of incident.damages) {
    if (d.amount < 0) {
      throw new Error(`Negative damage amount: ${d.amount}`);
    }
    damageCounts[d.itemType] = (damageCounts[d.itemType] || 0) + 1;
  }
  for (const [itemType, count] of Object.entries(damageCounts)) {
    if (!(itemType in policyCounts) || count > policyCounts[itemType]) {
      throw new Error(`Damage to item not in policy or exceeds covered count: ${itemType}`);
    }
  }

  // Build a pool of items per type to match damages to
  const itemPool: Record<string, Item[]> = {};
  for (const it of policy.items) {
    (itemPool[it.type] ||= []).push(it);
  }

  let totalRaw = 0;
  for (const d of incident.damages) {
    // Match to an item; prefer one matching characteristics doesn't matter — each entry is independent
    const pool = itemPool[d.itemType];
    const item = pool[0]; // representative; since damage entries don't carry item attrs, use any
    const p = payoutForDamage(item, d.amount);
    totalRaw += Math.max(0, p);
  }

  const finalPayoutRaw = Math.min(totalRaw, policy.remainingCap);
  const payout = Math.floor(finalPayoutRaw);
  return { payout, remainingCap: policy.remainingCap - payout };
}

export function processScenario(scenario: Scenario): ScenarioResults {
  const results: StepResult[] = [];
  const policies: Record<number, PolicyState> = {};
  let quoteCount = 0;

  for (let i = 0; i < scenario.steps.length; i++) {
    const step = scenario.steps[i];
    if (step.op === 'quote') {
      const { premium, insuranceSum } = computeQuote(step.items, {
        customer: scenario.customer,
        quoteIndex: quoteCount,
      });
      quoteCount++;
      const cap = insuranceSum * 2;
      policies[i] = {
        items: step.items,
        insuranceSum,
        cap,
        remainingCap: cap,
      };
      results.push({ premium });
    } else {
      const policy = policies[step.policy];
      if (!policy) {
        throw new Error(`Claim references unknown policy index: ${step.policy}`);
      }
      const { payout, remainingCap } = computeClaim(policy, step.incident);
      policy.remainingCap = remainingCap;
      results.push({ payout, remainingCap });
    }
  }

  return { results };
}

